```java
public record TradeExecutedEvent(
    String tradeId,
    String userId,
    String symbol,
    int quantity,
    double price,
    double totalValue,
    java.time.Instant executedAt
) {}

@Service
public class TradeEventPublisher {
    private final KafkaTemplate<String, TradeExecutedEvent> kafkaTemplate;

    TradeEventPublisher(KafkaTemplate<String, TradeExecutedEvent> kt) {
        kafkaTemplate = kt;
    }

    public void publishTradeExecuted(TradeExecutedEvent event) {
        kafkaTemplate.send("trade-events", event.symbol(), event)
            .whenComplete((result, ex) -> {
                if (ex != null) {
                    System.err.println("Failed to publish trade event: " + ex.getMessage());
                } else {
                    System.out.printf("Trade event published: symbol=%s offset=%d%n",
                        event.symbol(), result.getRecordMetadata().offset());
                }
            });
    }
}
```

```java
@Service
public class TradeService {
    private final TradeEventPublisher publisher;

    public TradeResult executeTrade(String userId, String symbol, int qty) {
        // ... trade logic ...
        TradeResult result = new TradeResult("TRD-001", symbol, qty, 3890.0);

        // Publish async — doesn't block the trade response:
        publisher.publishTradeExecuted(new TradeExecutedEvent(
            result.tradeId(), userId, symbol, qty,
            3890.0, qty * 3890.0, java.time.Instant.now()));

        return result;  // returned to user immediately
    }
}
```

